        howItHappens: 'Logout endpoints only delete client tokens but do not revoke refresh tokens or destroy server sessions.',
        properFix: 'On logout: revoke refresh tokens, destroy server sessions, and clear cookies with HttpOnly/Secure/SameSite. Rotate tokens to reduce replay risk.',
        hipaaReference: '45 CFR 164.312(a)(1) - Access control',
